__kernel void hotspotOpt1(__global const float *pIn, 
                          __global float *tIn, 
                          __global float *tOut, 
                          float stepDivCap,
                          int nx, int ny, int nz, 
                          float ce, float cw, float cn, float cs, float ct, float cb, float cc) 
{
    int x = get_global_id(0);
    int y = get_global_id(1);
    int z;

    if (x >= nx || y >= ny) return;

    float c_val, w_val, e_val, n_val, s_val, b_val, t_val;
    int c, w, e, n, s, b, t;

    for (z = 0; z < nz; z++) {
        c = x + y * nx + z * nx * ny;

        w = (x == 0) ? c : c - 1;
        e = (x == nx - 1) ? c : c + 1;
        n = (y == 0) ? c : c - nx;
        s = (y == ny - 1) ? c : c + nx;
        b = (z == 0) ? c : c - nx * ny;
        t = (z == nz - 1) ? c : c + nx * ny;

        c_val = tIn[c];
        w_val = tIn[w];
        e_val = tIn[e];
        n_val = tIn[n];
        s_val = tIn[s];
        b_val = tIn[b];
        t_val = tIn[t];

        tOut[c] = cc * c_val + cw * w_val + ce * e_val + cs * s_val + cn * n_val + cb * b_val + ct * t_val + stepDivCap * pIn[c] + ct * 80.0f;
    }
}
